import React, { useState } from 'react';
import './appoiment.css';

const Appointments = () => {
    const [showModal, setShowModal] = useState(false);
    const [appointments, setAppointments] = useState([
        { id: "APP-001", patient: "John Doe", doctor: "Dr. Smith", date: "2026-03-12", time: "10:30 AM", type: "Checkup", status: "Confirmed" },
    ]);

    // State for the Form Inputs
    const [formData, setFormData] = useState({
        patient: '',
        doctor: 'Dr. Smith',
        date: '',
        time: '',
        type: 'Checkup'
    });

    const handleSave = (e) => {
        e.preventDefault();
        const newAppt = {
            id: `APP-00${appointments.length + 1}`,
            ...formData,
            status: "Pending"
        };
        setAppointments([...appointments, newAppt]);
        setShowModal(false); // Close modal after saving
    };

    return (
        <div className="appt-page">
            <div className="appt-header">
                <h1>Appointments</h1>
                <button className="book-btn" onClick={() => setShowModal(true)}>+ Book Appointment</button>
            </div>

            {/* Appointment Table */}
            <div className="appt-table-container">
                <table className="appt-table">
                    <thead>
                        <tr>
                            <th>Time</th>
                            <th>Patient</th>
                            <th>Doctor</th>
                            <th>Status</th>
                        </tr>
                    </thead>
                    <tbody>
                        {appointments.map((appt) => (
                            <tr key={appt.id}>
                                <td className="time-cell">{appt.time}</td>
                                <td>{appt.patient}</td>
                                <td>{appt.doctor}</td>
                                <td><span className={`status-dot ${appt.status.toLowerCase()}`}>{appt.status}</span></td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* The "Add Appointment" Modal */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-box">
                        <h2>Book New Appointment</h2>
                        <form onSubmit={handleSave}>
                            <label>Patient Name</label>
                            <input 
                                type="text" 
                                required 
                                onChange={(e) => setFormData({...formData, patient: e.target.value})} 
                            />
                            
                            <div className="form-row">
                                <div className="form-group">
                                    <label>Date</label>
                                    <input type="date" required onChange={(e) => setFormData({...formData, date: e.target.value})} />
                                </div>
                                <div className="form-group">
                                    <label>Time</label>
                                    <input type="time" required onChange={(e) => setFormData({...formData, time: e.target.value})} />
                                </div>
                            </div>

                            <label>Doctor</label>
                            <select onChange={(e) => setFormData({...formData, doctor: e.target.value})}>
                                <option>Dr. Smith</option>
                                <option>Dr. Adams</option>
                                <option>Dr. Taylor</option>
                            </select>

                            <div className="modal-actions">
                                <button type="button" className="cancel-btn" onClick={() => setShowModal(false)}>Cancel</button>
                                <button type="submit" className="save-btn">Confirm Booking</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Appointments;
